INSERT INTO `timelineevents` VALUES (1,40,'40 - 43 SCN','40 – 43 AD','Cuộc khởi nghĩa Hai Bà Trưng','The Hai Ba Trung Uprising','Trưng Trắc, Trưng Nhị là hai chị em sinh đôi, con gái quan Lạc tướng Mê Linh (miền Sơn Tây cũ và tỉnh Vĩnh Phúc ngày nay), thuộc dòng dõi Hùng Vương. Mẹ là bà Man Thiện, người làng Nam Nguyễn - Ba Vì - Sơn Tây - Hà Nội. Chồng mất sớm, bà Man Thiện một mình nuôi dạy hai chị em Trưng Trắc, Trưng Nhị; bà dạy cho con nghề trồng dâu, nuôi tằm; dạy con lòng yêu nước, rèn luyện sức khỏe và võ nghệ. Trưng Trắc là một phụ nữ đảm đang, dũng cảm, mưu trí. Chồng bà là Thi Sách, con trai quan Lạc tướng huyện Chu Diên (Hà Nội). Gia đình Thi Sách là một gia đình yêu nước, có thế lực ở đất Chu Diên. Trưng Trắc và Trưng Nhị vốn được nhân dân Mê Linh tin phục. Từ lâu, hai chị em bà vẫn căm thù cuộc sống bạo ngược của viên thái thú nhà Đông Hán là Tô Định. Chính sách bạo ngược này thực ra là chính sách áp bức, bóc lột của nhà Đông Hán với toàn bộ người Âu Lạc, từ lạc tướng cho đến nô lệ.\nCuộc hôn nhân giữa Trưng Trắc và Thi Sách làm cho thế lực của bà - thế lực đối lập với chính quyền do Tô Định là đại biểu - lại càng lớn mạnh. Để tước bớt thế lực của gia đình Trưng Trắc đã lan ra khắp miền đất Vĩnh Phúc, Tô Định đã tìm cách giết chết Thi Sách. Hành vi bạo ngược của Tô Định không làm cho Trưng Trắc sờn lòng, mà trái lại càng làm cho bà thêm quyết tâm tiến hành cuộc khởi nghĩa đánh đổ chính quyền đô hộ, áp bức của nhà Đông Hán, khôi phục độc lập, \"đền nợ nước, trả thù nhà\".\nBà Trưng đã đặt nợ nước lên trên thù chồng. Trên dàn thề trước ba quân, bà nêu rõ 4 mục tiêu của cuộc khởi nghĩa:\n\nMột xin rửa sạch nước thù\n\nHai xin dựng lại nghiệp xưa họ Hùng\n\nBa kêu oan ức lòng chồng\n\nBốn xin vẻn vẹn sở công lênh này\n\nTháng 2 năm Canh Tý (năm 40), Trưng Trắc cùng với em gái là Trưng Nhị phát động khởi nghĩa ở cửa sông Hát (thuộc địa phận huyện Phúc Thọ - Hà Nội). Những người yêu nước khắp nơi rầm rập kéo về tụ nghĩa ở Mê Linh. Từ Mê Linh, nghĩa quân tiến về xuôi, tiến đánh Luy Lâu (Thuận Thành - Bắc Ninh) - thủ phủ của chính quyền nhà Đông Hán ở Giao Chỉ. Chế độ áp bức của nhà Hán bị quật đổ, Luy Lâu được giải phóng.\nTừ lâu người Việt Nam và các tộc người khác ở quận Giao Chỉ, quận Cửu Chân (nay là Thanh Hóa, Nghệ An, Hà Tĩnh), quận Nhật Nam (nay là miền đất từ dãy Hoành Sơn đến Quảng Nam) vô cùng căm giận chế độ áp bức, bóc lột tàn tệ của nhà Đông Hán. Cho nên khi chính quyền nhà Đông Hán bị đánh đổ ở Luy Lâu thì nhân dân trong các quận này hào hứng tham gia cầm vũ khí chống lại lũ quan lại và quân lính nhà Đông Hán. Được nhân dân khắp nơi ủng hộ, hưởng ứng, nghĩa quân của Hai Bà Trưng đi đến đâu, chính quyền và quân đội nhà Đông Hán tan vỡ đến đấy. Các dân tộc Mán, Lý ở Cửu Chân, Nhật Nam, Hợp Phố (nay thuộc Quảng Đông) đều hưởng ứng. Bọn Tô Định, Thứ sử, Thái thú của nhà Đông Hán thấy nghĩa quân nổi lên như vũ bão, đều hoảng sợ và theo nhau bỏ chạy về Trung Quốc. Dưới sự lãnh đạo của Hai Bà Trưng, các cuộc khởi nghĩa địa phương được thống nhất thành một phong trào nổi dậy rộng lớn của quần chúng ở khắp nơi, từ miền xuôi đến miền ngược, bao gồm cả người Việt và các dân tộc khác trong nước Âu Lạc cũ. \nChỉ trong một thời gian ngắn, Hai Bà Trưng đã giải phóng được 65 huyện thành, nghĩa là toàn bộ lãnh thổ nước Việt hồi đó. Cuộc khởi nghĩa thành công, đất nước được hoàn toàn độc lập. Trưng Trắc được suy tôn làm vua (Trưng Vương), đóng đô ở Mê Linh:\n\nĐô Kỳ đóng cõi Mê Linh\n\nLĩnh Nam riêng một triều đình nước ta\n\nHiểu rõ sự thống khổ của nhân dân nên khi lên ngôi vua, mặc dù chỉ trong thời gian ngắn nhưng Trưng Vương đã có những quyết sách quan trọng như: ra lệnh miễn thuế khóa cho nhân dân trong hai năm, xóa bỏ chế độ lao dịch và binh pháp cũ... Anh hùng dân tộc Trưng Vương đã lập nên và giữ vững nền độc lập, quyền tự chủ dân tộc trong gần 3 năm.\nCuộc khởi nghĩa do Hai Bà Trưng lãnh đạo đã lật nhào chính quyền nhà Đông Hán ở Giao Chỉ và Cửu Chân. Tin này đưa về triều đình nhà Hán. Vua Quang Vũ nhà Hán chuẩn bị cuộc phản công. Năm 42, Quang Vũ sai Phục ba tướng quân là Mã Viện, Lâu thuyền tướng quân là Đoàn Chí đem quân ở các miền Quế Dương, Linh Lăng, Thương Ngô sang nước Âu Lạc đánh Trưng Vương. Bộ binh của Mã Viện và thủy binh của Đoàn Chí gặp nhau ở Hợp Phố. Ở đây Đoàn Chí mắc bệnh rồi chết, Mã Viện thống suất cả thủy binh của Đoàn Chí. Mã Viện cùng quân đội men theo bờ biển tiến vào Âu Lạc. Đầu tiên quân Hán vào miền đất là tỉnh Hồng Quảng.Từ Hồng Quảng, quân Hán ngược sông Bạch Đằng tiến đến Lục đầu, sau đó tiến vào Lãng Bạc - Tiên Du - Bắc Ninh. Được tin quân xâm lược nhà Hán do Mã Viện chỉ huy tiến vào Lãng Bạc, Trưng Vương cùng em là Trưng Nhị đem quân từ Mê Linh đánh Mã Viện. Tại đây đã diễn ra một cuộc chiến đấu ác liệt giữa quân ta và bè lũ xâm lược. Quân của Trưng Vương chiến đấu rất dũng cảm, song do thế yếu nên bị thua, phải lui về Cẩm Khê (Yên Lạc - Vĩnh Phúc). Mã Viện đem quân đuổi theo. Sau gần 1 năm anh dũng chống địch, cuối cùng vì sức yếu, quân ta tan vỡ. Hai Bà Trưng về Hát Môn (Phúc Thọ - Hà Nội) rồi gieo mình xuống dòng Hát giang tự tận. Đến đây cuộc kháng chiến do Hai Bà Trưng lãnh đạo về căn bản đã thất bại, nhưng ở nhiều nơi nhân dân và nghĩa quân vẫn tiếp tục chống giặc. Ở quận Cửu Chân, một bộ phận của nghĩa quân do Đô Đương chỉ huy vẫn tiếp tục chiến đấu chống quân xâm lược nhà Đông Hán.\nTháng 11/43, Mã Viện mở đường qua Tạc Khẩu (Yên Mô - Ninh Bình) tiến quân vào Cửu Chân đàn áp nghĩa quân. Các thủ lĩnh địa phương cùng nhân dân nơi đây tiếp tục chiến đấu anh dũng. Hàng trăm thủ lĩnh, hàng ngàn nghĩa quân bị Mã Viện tàn sát. Đất nước ta lại mất quyền độc lập. Cuộc khởi nghĩa của Hai Bà Trưng tuy chỉ đưa lại độc lập cho đất nước trong gần 3 năm nhưng ý nghĩa lịch sử của cuộc khởi nghĩa ấy lại vô cùng vĩ đại, tiếng vang của nó đời đời bất diệt. Hai Bà Trưng là biểu tượng của ý chí hiên ngang và khí phách quật cường của dân tộc ta; thể hiện truyền thống yêu nước nồng nàn của phụ nữ Việt Nam \"giặc đến nhà, đàn bà cũng đánh\" trong những năm 40 sau Công nguyên. Phụ nữ Việt Nam ngay từ thời cổ đại không những khẳng khái, bất khuất mà còn có khả năng lãnh đạo sự nghiệp đấu tranh giải phóng dân tộc và xây dựng đất nước.','Trung Trac and Trung Nhi were twin sisters, the daughters of Lac Tuong Me Linh (of the former Son Tay region and present-day Vinh Phuc Province), descended from the Hung Kings. Their mother was Lady Man Thien, a native of Nam Nguyen village, Ba Vi, Son Tay, Hanoi. After her husband’s early death, Lady Man Thien raised the two sisters, Trung Trac and Trung Nhi, on her own; she taught them the craft of mulberry cultivation and silkworm rearing; she instilled in them a love of country, and trained them in physical fitness and martial arts. Trung Trac is a confident, brave and cunning woman. Her husband is Thi Sach, the son of the general of Chu Dien district (Hanoi). Thi Sach\'s family is a patriotic and influential family in the land of Chu Dien. Trung Trac and Trung Nhi were originally trusted by Me Linh people. For a long time, the two sisters still hated the tyrannical life of the governor of the Eastern Han Dynasty, To Dinh. This tyrannical policy is actually the policy of oppression and exploitation of the Eastern Han dynasty against all Au Lac people, from generals to slaves.\nThe marriage between Trung Trac and Thi Sach made her power - the force opposing the government represented by To Dinh - even stronger. To strip away the power of the Trung Trac family that had spread throughout Vinh Phuc, To Dinh tried to kill Thi Sach. To Dinh\'s tyrannical behavior did not weaken Trung Trac\'s heart, but on the contrary, it made her even more determined to carry out an uprising to overthrow the colonial and oppressive government of the Eastern Han Dynasty, restore independence, \"repay the country\'s debt, and take revenge on the family\".\nMrs. Trung put the country\'s debt above her husband\'s hatred. On the oath in front of the three armies, she clearly stated the four goals of the uprising: One, to wash away the enemy\'s country, Two, to rebuild the Hung family\'s past karma, Three, to unjustly resent her husband, Four, to complete this order. In February of the year of Canh Ty (40), Trung Trac and his younger sister, Trung Nhi, launched an uprising at the mouth of the Hat River (in Phuc Tho district - Hanoi). Patriots from everywhere flocked to gather in Me Linh. From Me Linh, the insurgent army moved downstream, attacking Luy Lau (Thuan Thanh - Bac Ninh) - the capital of the Eastern Han government in Giao Chi. The oppressive regime of the Han Dynasty was overthrown and Luy Lau was liberated.\nMrs. Trung put the country\'s debt above her husband\'s hatred. On the oath in front of the three armies, she clearly stated the four goals of the uprising:\n \nOne, to wash away the enemy\'s country,\n\nTwo, to rebuild the Hung family\'s past karma,\n\nThree, to unjustly resent her husband, \n\nFour, to complete this order. \n\nIn February of the year of Canh Ty (40), Trung Trac and his younger sister, Trung Nhi, launched an uprising at the mouth of the Hat River (in Phuc Tho district - Hanoi). Patriots from everywhere flocked to gather in Me Linh. From Me Linh, the insurgent army moved downstream, attacking Luy Lau (Thuan Thanh - Bac Ninh) - the capital of the Eastern Han government in Giao Chi. The oppressive regime of the Han Dynasty was overthrown and Luy Lau was liberated.\nFor a long time, Vietnamese people and other ethnic groups in Giao Chi district, Cuu Chan district (now Thanh Hoa, Nghe An, Ha Tinh), Nhat Nam district (now the land from the Hoanh Son range to Quang Nam) have been extremely angry with the brutal oppressive and exploitative regime of the Eastern Han Dynasty. So when the Eastern Han government was overthrown in Luy Lau, the people in these districts excitedly took up arms against the Eastern Han mandarins and soldiers. \nSupported and responded to by people everywhere, wherever the Trung Sisters\' insurgent army went, the Eastern Han government and army collapsed. The Man and Ly ethnic groups in Cuu Chan, Nhat Nam, and Hop Pho (now in Guangdong) all responded. When To Dinh, the Governor, and the Governor of the Eastern Han Dynasty saw the insurgents rising like a storm, they all panicked and fled back to China. \nUnder the leadership of Hai Ba Trung, local uprisings were unified into a large uprising movement of the masses everywhere, from the lowlands to the uplands, including Vietnamese and other ethnic groups in the old Au Lac country.\nIn just a short time, Hai Ba Trung liberated 65 districts, meaning the entire territory of Vietnam at that time. The uprising was successful, the country was completely independent. Trung Trac was honored as king (Trung Vuong), with the capital in Me Linh: \n\nDo Ky occupied Me Linh \n\nLinh Nam with a separate court in our country. \n\nUnderstanding the suffering of the people, when he ascended the throne, although only for a short time, Trung Vuong made important decisions such as: ordering tax exemption for the people for two years, abolishing the old forced labor regime and military tactics... National hero Trung Vuong established and maintained national independence and autonomy for nearly 3 years.\nThe uprising led by the Trung Sisters overthrew the Eastern Han government in Giao Chi and Cuu Chan. This news was brought to the Han court. King Quang Vu of the Han Dynasty prepared a counterattack. In the year 42, Quang Vu ordered Phuc three generals, Ma Vien, and Lau boat general Doan Chi, to bring troops from the regions of Que Duong, Linh Lang, and Thuong Ngo to Au Lac country to attack Trung Vuong. Ma Vien\'s infantry and Doan Chi\'s navy met at Hop Pho. Here, Doan Chi fell ill and died. Ma Vien commanded Doan Chi\'s navy. Ma Vien and his army followed the coast to Au Lac. The first Han army entered the land of Hong Quang province. From Hong Quang, the Han army went up Bach Dang river to Luc Dau, then entered Lang Bac - Tien Du - Bac Ninh. Hearing that the Han invaders led by Ma Vien were entering Lang Bac, Trung Vuong and his brother Trung Nhi led troops from Me Linh to attack Ma Vien. Here a fierce battle took place between our army and the invading gang. Trung Vuong\'s army fought very bravely, but due to their weak position, they lost and had to retreat to Cam Khe (Yen Lac - Vinh Phuc). Ma Vien led his army to chase. After nearly a year of heroically fighting the enemy, in the end, due to weakness, our army collapsed. The Trung sisters returned to Hat Mon (Phuc Tho - Hanoi) and then threw themselves into the Hat river and committed suicide. At this point, the resistance war led by Hai Ba Trung basically failed, but in many places the people and insurgents continued to fight the enemy. In Cuu Chan district, a part of the insurgent army led by Do Duong continued to fight against the Eastern Han invaders.\nIn November 43, Ma Vien opened the way through Tac Khau (Yen Mo - Ninh Binh) to march into Cuu Chan to suppress the insurgents. Local leaders and people here continued to fight heroically. Hundreds of leaders and thousands of insurgents were massacred by Ma Vien. Our country lost its independence again. Although the uprising of the Trung Sisters only brought independence to the country for nearly 3 years, the historical significance of that uprising was extremely great, its echo is eternal. The Trung Sisters are symbols of our nation\'s courageous will and tenacious spirit; demonstrates the passionate patriotic tradition of Vietnamese women \"when the enemy comes to the house, women also fight\" in the 40s AD. Vietnamese women since ancient times have not only been assertive and indomitable but also had the ability to lead the cause of national liberation and national construction.','/uploads/1775576145712-414147591.jpg','2026-04-02 16:48:46','2026-04-07 15:35:50'),(2,248,'248','248','Cuộc khởi nghĩa bà Triệu',' The Lady Trieu\'s Uprising','Cuộc khởi nghĩa của bà Triệu diễn ra trong bối cảnh đất nước đang trong giai đoạn Bắc thuộc kéo dài, nhiều phong trào quần chúng nổi dậy chống lại ách đô hộ của các triều đại phương Bắc. Trong khi đó, tình hình chính trị cực kỳ phức tạp, các bộ tộc, dân tộc thiểu số vùng Đông Bắc muốn thoát khỏi sự áp bức và giành lại nền tự chủ của mình.\n\nThời kỳ Bắc thuộc của các triều đại phong kiến phương Bắc bắt đầu từ thời nhà Triệu, Triệu Đà, nhưng đặc biệt với các triều đại như hậu Hán, Tần, Đông Hán, và quan trọng nhất là thế kỷ thứ 3, tình hình bị kiểm soát chặt chẽ hơn. Người Việt trong các giai đoạn này thường xuyên nổi dậy chống lại sự đô hộ, khẳng định chủ quyền tự nhiên của dân tộc và khát vọng độc lập.\n\nTrong hoàn cảnh đó, nhân dân Đông Bắc Việt Nam nổi lên như một lực lượng kháng chiến, trong đó bà Triệu trở thành biểu tượng tiêu biểu cho tinh thần quật khởi, dám đứng lên chống lại giặc ngoại xâm khi đất nước lâm nguy. Bà không những là người lãnh đạo mà còn là hình tượng của lòng yêu nước, của sức mạnh lòng dân trong những thời khắc hiểm nghèo.\n\nBà Triệu còn gọi là Triệu Thị Trinh, sinh ra trong một gia đình nông dân, đã sớm thể hiện tinh thần yêu nước mãnh liệt và lòng dũng cảm kiên cường. Bà là người phụ nữ đầu tiên dám đứng lên lãnh đạo phong trào khởi nghĩa trong bối cảnh xã hội phong kiến đương thời còn nhiều định kiến về vai trò của phụ nữ trong chiến tranh.\nVai trò của bà Triệu không chỉ dừng lại ở việc lãnh đạo quân khởi nghĩa mà còn truyền cảm hứng cho toàn thể dân chúng vùng Đông Bắc. Bà là biểu tượng cho sức mạnh tinh thần bất khuất của người phụ nữ Việt Nam, biểu tượng của ý chí không khuất phục trước ngoại xâm. Hình ảnh bà Triệu trượng nghĩa, dũng mãnh đã trở thành huyền thoại sống trong lòng người dân qua nhiều thế hệ.\n\nCuộc khởi nghĩa năm 248 xuất phát từ các nguyên nhân chủ yếu như áp lực của chính quyền đô hộ Ngô, sự đàn áp tàn bạo đối với nhân dân, cùng với ý thức dân tộc dâng cao của người dân vùng Đông Bắc muốn giải phóng khỏi sự bóc lột của ngoại bang. Người dân nơi đây đã chứng kiến cảnh đất đai bị cướp phá, cuộc sống khó khăn lê thê, cùng với lòng tự tôn dân tộc bị xúc phạm.\n\nNgoài ra, các phong trào khởi nghĩa liên tiếp diễn ra trong thời kỳ này cũng tạo nên khí thế, thúc đẩy lòng yêu nước, khơi nguồn ý chí giành độc lập ở đám đông nhân dân. Đặc biệt, sự xuất hiện của bà Triệu như một nhân vật lãnh đạo có tầm nhìn chiến lược và tinh thần chiến đấu kiên cường đã góp phần làm bùng nổ phong trào đấu tranh nơi vùng Đông Bắc.\n\nCuộc khởi nghĩa của bà Triệu diễn ra trong một bối cảnh hỗn loạn, nhưng tinh thần chiến đấu của nhân dân và của chính bà đã tạo nên một chuỗi các hoạt động vũ trang và đấu tranh dữ dội, nhằm chống lại sự xâm lấn của giặc Ngô. Cuộc khởi nghĩa bà triệu năm 248 là một dấu mốc quan trọng của lịch sử đánh giặc ngoại xâm.\nSau khi nhận thức rõ nguy cơ mất đất, bà Triệu đã nhanh chóng tập hợp lực lượng, kêu gọi quần chúng tham gia khởi nghĩa. Với tài năng lãnh đạo và khả năng hùng biện, bà đã thuyết phục được nhiều chiến binh và nhân dân vùng Đông Bắc đứng lên nổi dậy, chuẩn bị cho cuộc chiến chống lại quân Ngô.\n\nChịu ảnh hưởng của các phong trào chống xâm lược trước đó, bà Triệu đã xây dựng các chiến lược đấu tranh dựa trên sự hiểu biết về địa hình, khí hậu địa phương. Lí tưởng đấu tranh chống giặc ngoại xâm đã trở thành mục tiêu chung, tạo nên khí thế sôi sục trong cộng đồng. Việc tập hợp lực lượng không chỉ đơn thuần là về quân số, mà còn là một cuộc vận động tinh thần, thúc đẩy mọi người cùng ý chí chiến đấu do bà lãnh đạo.\n\nCác trận đánh do bà Triệu chỉ huy đều mang tinh thần chiến tranh du kích, tận dụng tối đa địa hình rừng núi, khe suối để gây bất ngờ cho địch. Một trong những trận đấu nổi bật nhất là trận chống lại quân Ngô khi họ tiến vào vùng đất của bà Triệu. \n\nTrong trận chiến này, bà Triệu đã vận dụng các chiến thuật đặc biệt như phục kích, tấn công bất ngờ, gây tổn thất lớn cho địch. Sự dũng mãnh và khả năng chỉ huy tuyệt vời của bà đã giúp quân khởi nghĩa giữ vững thế trận trong thời gian dài, tạo niềm tin cho nhân dân về khả năng thắng lợi cuối cùng. Những chiến công ban đầu này đã góp phần xây dựng uy thế và khí thế chiến tranh của cuộc khởi nghĩa.\n\nBà Triệu dùng chiến lược phòng thủ tích cực, phối hợp chiến thuật du kích, chiến tranh tâm lý và vận động chính trị, nhằm chia rẽ lực lượng địch và nâng cao tinh thần chiến đấu của bộ đội khởi nghĩa. Bà luôn chuẩn bị sẵn sàng cho các trận chiến nhỏ, tận dụng tối đa địa hình để gây bất ngờ và đối đầu cam go với quân Ngô.\n\nNgoài ra, bà còn khéo léo sử dụng các mối quan hệ liên minh, đấu tranh chính trị để mở rộng ảnh hưởng và huy động thêm lực lượng. Chiến lược của bà thường xuyên đổi mới, linh hoạt, nhằm thích ứng với từng giai đoạn của cuộc chiến, cho thấy khả năng chiến lược và tư duy sáng tạo của một nhà lãnh đạo xuất chúng.\n\nSau các trận đánh ban đầu thành công, phong trào khởi nghĩa của bà Triệu nhanh chóng lan rộng đến nhiều địa phương hơn. Các khu vực xung quanh đều bắt đầu nổi dậy, tạo thành một phong trào chống Ngô kéo dài và có tổ chức.\n\nKhí thế đấu tranh lan tỏa, thúc đẩy tinh thần tự quyết của nhân dân các vùng, và làm dấy lên một làn sóng phản kháng dữ dội. Sự mở rộng này còn thể hiện qua việc các phong trào dân tộc phản kháng trở thành một phần không thể tách rời của phong trào chống giặc xâm lược thời kỳ đó, góp phần dựng lên hình ảnh của bà Triệu như một biểu tượng của đất nước trong thời kỳ đen tối. \n\nDù khí thế ban đầu rất sôi động, cuộc khởi nghĩa của bà Triệu cuối cùng cũng đi đến kết cục không như mong đợi. Đánh giá nguyên nhân thất bại, chúng ta có thể thấy nhiều yếu tố nhỏ lẻ, do chính sách đàn áp của địch, cũng như thiếu sự hỗ trợ từ các lực lượng khác của đất nước.\n\nMột trong những lý do chính dẫn đến thất bại là vì sức mạnh của quân Ngô quá lớn, có trang thiết bị và quân số vượt trội, trong khi phong trào khởi nghĩa còn thiếu sự liên kết và tổ chức sâu rộng. Bên cạnh đó, việc thiếu sự phối hợp chiến lược với các lực lượng khác của nhà nước đã khiến phong trào mất dần sức mạnh và chấm dứt sớm.\n\nNgoài ra, các chính sách đòn phủ đầu, đàn áp tàn bạo từ phía địch cùng sự phân cực nội bộ, đã làm giảm tinh thần binh sĩ và nhân dân, dẫn đến sự suy yếu dần của cuộc khởi nghĩa. Khí thế ban đầu bị kiểm soát và thấm đượm tinh thần tự do, tự chủ bỗng chốc biến mất khi địch phản công dữ dội.\n','Ms. Trieu\'s uprising took place in the context of the country being in a prolonged period of Northern domination, with many mass movements rebelling against the domination of the Northern dynasties. Meanwhile, the political situation is extremely complicated, tribes and ethnic minorities in the Northeast want to escape oppression and regain their autonomy.\n\nThe period of Northern domination of the Northern feudal dynasties began from the Trieu and Trieu Da dynasties, but especially with dynasties such as the later Han, Qin, Eastern Han, and most importantly the 3rd century, the situation was more strictly controlled. Vietnamese people during these periods often rebelled against colonization, affirming the nation\'s natural sovereignty and aspiration for independence.\n\nIn that situation, the people of Northeast Vietnam emerged as a resistance force, in which Ms. Trieu became a symbol of the spirit of rebellion, daring to stand up against foreign invaders when the country was in danger. She is not only a leader but also an image of patriotism and the strength of the people\'s hearts in dangerous times.\n\nMrs. Trieu, also known as Trieu Thi Trinh, was born into a farmer family, and soon demonstrated a strong patriotism and resilient courage. She was the first woman who dared to stand up and lead the uprising movement in a context where contemporary feudal society still had many prejudices about the role of women in war. Ms. Trieu\'s role not only stopped at leading the uprising but also inspired the entire population of the Northeast. She is a symbol of the indomitable spiritual strength of Vietnamese women, a symbol of the will not to yield to foreign invaders. The image of Ms. Trieu, righteous and brave, has become a living legend in the hearts of people for many generations.\n\nThe uprising in 248 stemmed from main causes such as pressure from the Ngo colonial government, brutal repression of the people, along with the rising national consciousness of the people of the Northeast who wanted to be liberated from foreign exploitation. People here have witnessed land being looted, life being difficult, and national pride being insulted.\n\nIn addition, the continuous uprising movements that took place during this period also created momentum, promoted patriotism, and inspired the will for independence in the masses. In particular, the appearance of Ms. Trieu as a leader with strategic vision and resilient fighting spirit contributed to the explosion of the struggle movement in the Northeast region.\n\nMs. Trieu\'s uprising took place in a chaotic context, but the fighting spirit of the people and her own created a series of armed activities and fierce struggles to resist the invasion of the Ngo invaders. The 248-year-old uprising was an important milestone in the history of fighting foreign invaders.\nAfter clearly realizing the risk of losing her land, Ms. Trieu quickly gathered forces and called on the masses to join the uprising. With her leadership talent and eloquence, she convinced many warriors and people in the Northeast to rise up and prepare for the war against the Ngo army.\n\nInfluenced by previous anti-invasion movements, Ms. Trieu built fighting strategies based on an understanding of the local terrain and climate. The ideal of fighting against foreign invaders has become a common goal, creating a vibrant atmosphere in the community. The gathering of forces is not simply about numbers, but also a spiritual campaign, motivating everyone with the will to fight under her leadership.\n\nIn this battle, Ms. Trieu used special tactics such as ambushes and surprise attacks, causing great losses to the enemy. Her courage and excellent command ability helped the rebels maintain their position for a long time, giving the people confidence in the possibility of final victory. These initial victories contributed to building the prestige and war spirit of the uprising.\n\nMs. Trieu used an active defense strategy, combining guerrilla tactics, psychological warfare and political mobilization, to divide enemy forces and raise the fighting spirit of the insurgent soldiers. She was always prepared for small battles, making the most of the terrain to surprise and confront the Ngo army.\n\nIn addition, she also skillfully used alliance relationships and political struggles to expand her influence and mobilize more forces. Her strategies were constantly innovative and flexible, adapting to each stage of the war, showing the strategic ability and creative thinking of an outstanding leader.\n\nAfter initial successful battles, Ms. Trieu\'s uprising quickly spread to more localities. The surrounding areas all began to rebel, forming a long and organized anti-Wu movement.\n\nThe fighting spirit spread, promoting the spirit of self-determination among the people of the regions, and giving rise to a wave of fierce resistance. This expansion was also shown through the national protest movements becoming an inseparable part of the anti-invasion movement of that period, contributing to building the image of Ms. Trieu as a symbol of the country during the dark period.\n\nAlthough the initial atmosphere was very exciting, Ms. Trieu\'s uprising eventually came to an unexpected outcome. Assessing the cause of failure, we can see many small factors, due to the enemy\'s repression policy, as well as lack of support from other forces of the country.\n\nOne of the main reasons for the failure was because the strength of the Ngo army was too great, with superior equipment and numbers, while the uprising movement lacked deep connection and organization. Besides, the lack of strategic coordination with other state forces caused the movement to lose strength and end prematurely.\n\nIn addition, pre-emptive policies, brutal repression from the enemy and internal polarization reduced the morale of soldiers and people, leading to the gradual weakening of the uprising. The initial atmosphere of being controlled and imbued with the spirit of freedom and self-reliance suddenly disappeared when the enemy counterattacked fiercely.','/uploads/1775578046488-291306175.jpg','2026-04-02 17:47:25','2026-04-07 16:07:30'),(3,-2879,'2879 TCN - 258 TCN','2879 BCE - 258 BCE','Thời kỳ Hùng Vương','Hung Kings Period','     Lịch sử thời kỳ Hùng Vương bắt nguồn từ sự chuyển mình mạnh mẽ của các bộ lạc cư dân văn hóa Đông Sơn. Vào khoảng thế kỷ VII TCN, tại vùng đồng bằng sông Hồng, sông Mã và sông Cả, nhu cầu trị thủy để làm lúa nước và sự cần thiết phải đoàn kết chống giặc ngoại xâm đã thúc đẩy các bộ lạc liên kết lại. Theo truyền thuyết, Lạc Long Quân và Âu Cơ chính là cội nguồn của dân tộc, còn sử liệu khẳng định thủ lĩnh bộ lạc Văn Lang đã thống nhất 15 bộ lạc, tự xưng là Hùng Vương, đóng đô tại Phong Châu (Phú Thọ). Đây là cột mốc đánh dấu sự ra đời của nhà nước sơ khai, đặt nền móng cho chủ quyền lãnh thổ của người Việt cổ.\n     Nhà nước Văn Lang tuy còn đơn giản nhưng đã có hệ thống phân cấp rõ rệt. Đứng đầu là Hùng Vương (cha truyền con nối), giúp việc có các Lạc hầu, Lạc tướng cai quản các bộ và Bồ chính cai quản các chiềng, chạ. Đây là thời kỳ đỉnh cao của kỹ thuật đúc đồng với biểu tượng là Trống đồng Đông Sơn. Cư dân Lạc Việt đã thuần thục việc trồng lúa nước, chăn nuôi và làm nghề thủ công. Hình thành nên những nét bản sắc độc đáo vẫn còn lưu giữ đến nay như tục nhuộm răng, ăn trầu, làm bánh chưng, bánh giầy và tinh thần cộng đồng sâu sắc.\n     Trải qua 18 đời vua, thời kỳ Hùng Vương không chỉ là giai đoạn định hình bản sắc văn hóa mà còn là thời kỳ đấu tranh bền bỉ để bảo vệ bờ cõi. Những truyền thuyết như Thánh Gióng hay Sơn Tinh - Thủy Tinh chính là hình ảnh phản chiếu của quá trình chống thiên tai và địch họa. Tuy nhiên, đến khoảng thế kỷ III TCN, trước sự lớn mạnh của người Âu Việt và áp lực từ nhà Tần, Thục Phán đã thống nhất hai tộc người Âu - Lạc, tiếp nối di sản của các vua Hùng để lập nên nhà nước Âu Lạc. Dù chuyển sang một thời đại mới, nhưng giá trị cốt lõi về tinh thần đoàn kết và ý thức cội nguồn của thời đại Hùng Vương đã trở thành sức mạnh trường tồn của dân tộc Việt Nam.','     The history of the Hung Kings era stems from a significant transformation among the tribes of the Dong Son culture. Around the 7th century BC, in the plains of the Red River, Ma River and Ca River, the need for flood control to cultivate paddy fields and the necessity to unite against foreign invaders prompted the tribes to form alliances. According to legend, Lac Long Quan and Au Co are the progenitors of the Vietnamese people, whilst historical records confirm that the leader of the Van Lang tribe unified 15 tribes, proclaimed himself Hung Vuong, and established his capital at Phong Chau (Phu Tho). This marked the birth of an early state, laying the foundations for the territorial sovereignty of the ancient Vietnamese.\n     Although the Van Lang state was still relatively simple, it already had a clearly defined hierarchical system. At the head was the Hung King (a hereditary monarchy), assisted by the Lac Hau and Lac Tuong, who governed the various clans, and the Bo Chinh, who administered the villages and hamlets. This was the golden age of bronze casting, symbolised by the Dong Son bronze drums. The Lac Viet people had mastered the cultivation of paddy rice, livestock rearing and handicrafts. These have given rise to unique cultural traditions that are still practised today, such as tooth blackening, betel nut chewing, the making of banh chung and banh giay, and a strong sense of community.\n     Spanning 18 generations of kings, the Hung Kings’ era was not only a period of cultural identity formation but also a time of relentless struggle to defend the nation’s borders. Legends such as Saint Giong or Son Tinh and Thuy Tinh reflect the struggle against natural disasters and foreign threats. However, by around the 3rd century BC, faced with the growing power of the Au Viet people and pressure from the Qin dynasty, Thuc Phan unified the Au and Lac tribes, continuing the legacy of the Hung Kings to establish the Au Lac state. Although a new era had dawned, the core values of solidarity and a sense of heritage from the era of the Hung Kings became the enduring strength of the Vietnamese nation.','/uploads/1775574577750-441220655.jpg','2026-04-07 15:09:39','2026-04-07 15:09:39'),(4,938,'938','938','Chiến thắng Bạch Đằng','Bach Dang Victory','Ở Trung Quốc, năm 907 nhà Đường sụp đổ. Các tập đoàn phong kiến quân phiệt phương Bắc vừa thôn tính, tiêu diệt nhau đẫm máu, vừa tận dụng mọi cơ hội bành trướng xâm lược ra bên ngoài.\n\nVua Nam Hán là Lưu Nghiễm (sau đổi là Lưu Cung) đã đặt tên nước là Đại Hán với tham vọng kế tục mộng bành trướng của đế chế Đại Hán hồi đầu Công nguyên. Hướng bành trướng chủ yếu của Nam Hán là phương Nam, nhằm vào đất nước ta, một đất nước giàu có và giữ vị trí trọng yếu của vùng Đông Nam Á, lại vừa qua hơn nghìn năm Bắc thuộc.\n\nThực hiện mộng bành trướng đó, năm 930, vua Nam Hán đã mở cuộc chiến tranh xâm lược lần thứ nhất. Chúng đã đánh bại được chính quyền họ Khúc, chiếm được phủ thành Đại La. Năm 931, một tướng của họ Khúc là Dương Đình Nghệ đã dấy quân từ châu Ái, nhanh chóng quét sạch quân giặc ra khỏi nước nhà, giành lại chủ quyền dân tộc.\n\nNăm 937, Dương Đình Nghệ bị Kiều Công Tiễn ám hại để đoạt chức Tiết độ sứ. Kiều Công Tiễn đã cho người sang cầu cứu vua Nam Hán. Nhân thời cơ đó, Nam Hán phát động cuộc chiến tranh xâm lược nước ta lần thứ hai.\n\nLần này, vua Nam Hán sai con trai là Thái tử Giao Vương Lưu Hoằng Tháo thống lĩnh quân thủy vượt biển tiến vào nước ta. Vua Nam Hán cũng đích thân đem quân áp sát biên giới để yểm trợ, gây thanh thế cho con và sẵn sàng tiếp ứng khi cần thiết.\n\nĐến tháng 10 năm 938, Ngô Quyền từ vùng châu Ái đem quân ra đánh Kiều Công Tiễn, trừ mối họa bên trong và làm thất bại ngay từ đầu âm mưu dùng nội ứng của Nam Hán. Sau đó, ông huy động nhân dân cả nước khẩn trương bước vào cuộc kháng chiến chống quân xâm lược Nam Hán.\n\nTrên cơ sở phát huy sức mạnh đoàn kết và khí thế độc lập của dân tộc, phân tích và đánh giá chỗ mạnh, chỗ yếu của ta và của địch, Ngô Quyền bày một thế trận hết sức kiên quyết, chủ động và lợi hại để nhanh chóng phá tan quân giặc.\n\nÔng huy động nhân dân đẵn gỗ, vót nhọn, bịt sắt, đóng thành một bãi cọc ở cửa sông Bạch Đằng. Quân thủy bộ với sự tham gia của các lực lượng dân binh, bố trí mai phục sẵn ở phía trong bãi cọc, vùng hạ lưu sông Bạch Đằng. Một đội thuyền nhẹ dưới quyền chỉ huy của người thanh niên Gia Viện (Hải Phòng) là Nguyễn Tất Tố, giỏi bơi lội và quen thuộc sông nước, được giao nhiệm vụ khiêu chiến, nhân lúc nước triều lên nhử địch vượt qua bãi cọc, dấn thân vào cạm bẫy mai phục bên trong của ta.\n\nBạch Đằng là cửa ngõ phía Đông Bắc của Tổ quốc ta, như tác giả bộ sử \"Cương mục\": \"Sông rộng hơn hai dặm, ở đó có núi cao ngất, nhiều nhánh sông đổ lại, sóng cồn man mác giáp tận chân trời, cây cối um tùm che lấp bờ bến\". Ngô Quyền không những biết lợi dụng địa hình thiên nhiên, để ém quân mai phục, phối hợp bộ binh với thủy binh, ông còn là người biết lợi dụng thủy triều sớm nhất trong lịch sử quân sự nước ta, gắn với việc bố trí bãi cọc ngầm nổi tiếng.\n\nTrong thế trận của Ngô Quyền, trận địa mai phục bên trong bãi cọc giữ vai trò quyết định, chặn đứng đoàn thuyền địch và giáng cho chúng một đòn tiêu diệt bất ngờ, nặng nề. Trận địa cọc giữ vai trò quan trọng, khóa đường tháo chạy của chiến thuyền địch và bao vây tiêu diệt triệt để quân giặc. Sự phối hợp giữa hai trận địa chứng tỏ quyết tâm chiến lược của Ngô Quyền là phen này không chỉ đánh bại quân giặc mà còn bao vây, tiêu diệt toàn bộ binh thuyền của giặc, giành thắng lợi oanh liệt, đập tan mộng xâm lược bành trướng của triều Nam Hán. \"Trận địa cọc\" là một nét độc đáo của trận Bạch Đằng, cũng là một sáng tạo rất sớm trong nghệ thuật quân sự Việt Nam mà người khởi xướng là Ngô Quyền.\n\nCuộc kháng chiến chống quân xâm lược Nam Hán trên sông Bạch Đằng đã diễn ra ác liệt và kết thúc rất nhanh gọn.\n\nNgô Quyền trực tiếp chỉ huy quân mai phục sẵn ở phía trong bãi cọc, dấu quân trong các nhánh sông và bên hữu ngạn sông Bạch Đằng.\n\nKhi cả binh đoàn thuyền lớn của Hoằng Tháo ào ạt vượt cửa biển An Bang tiến vào cửa ngõ Bạch Đằng, Ngô Quyền cho bộ phận tiên phong dùng thuyền nhẹ ra đón đánh địch từ xa, nghi binh dụ địch. Lúc thủy triều lên to ngập trận địa cọc, bộ phận này giả thua rút chạy nhử địch vào trận địa đúng lúc, đúng chỗ. Tướng Hoằng Tháo kiêu ngạo thúc đại quân đuổi gấp, trúng kế, mắc mưu, vượt qua bãi cọc ngầm.\n\nĐợi thủy triều xuống, Ngô Quyền mới cho quân mai phục đổ ra bao vây thuyền địch. Thuyền địch va vào cọc nhọn bịt sắt bị đâm thủng, chìm đắm gần hết, quân chết đuối quá nửa. Hoằng Tháo bị giáo đâm, lăn xuống nước chết tại trận. Quân ta giết và bắt sống hầu hết quân Nam Hán. Thời gian trận đánh chỉ diễn ra trong phạm vi một ngày. Chiến thắng Bạch Đằng nhanh gọn, bất ngờ đến mức vua Nam Hán đang cầm quân tiếp ứng đóng ở biên giới mà không kịp trở tay đối phó. Hắn kinh hoàng, khủng khiếp, đành \"thương khóc thu nhặt quân còn sót lại mà rút lui\" (Đại Việt sử ký toàn thư) và \"đem dư chúng quay trở lại\" (Ngũ đại sử ký).\n\nChiến thắng Bạch Đằng năm 938 đã ghi vào lịch sử dân tộc nói chung và lịch sử chống ngoại xâm nói riêng, như một sự kiện trọng đại có vị trí và ý nghĩa lịch sử hết sức lớn lao. Đây được coi là cột mốc quan trọng trong tiến trình lịch sử Việt Nam. Chiến thắng đã giúp phá bỏ nền thống trị hơn 1.000 năm của phong kiến phương Bắc, mở ra thời kỳ độc lập thực sự và lâu dài của dân tộc ta.\n\nNgô Quyền - người anh hùng của chiến thắng oanh liệt trên sông Bạch Đằng năm 938 - trở thành vị vua có \"công tái tạo, vua của các vua\" theo như nhận định của Đại Việt sử ký toàn thư. Ông xứng đáng với danh hiệu là \"vị tổ trung hưng\" của dân tộc như nhà yêu nước Phan Bội Châu lần đầu tiên đã nêu lên trong Việt Nam quốc sử khảo.\n\nMùa xuân năm Kỷ Hợi (939), Ngô Quyền quyết định bỏ chức Tiết độ sứ, tự xưng vương lấy hiệu là Ngô Vương Quyền, thành lập một vương quốc độc lập. Chọn kinh đô cũ của Âu Lạc là Cổ Loa làm kinh đô nước Việt để tỏ ý nối tiếp truyền thống của các vua Hùng, vua Thục.\n\nNgợi ca Ngô Quyền và chiến thắng Bạch Đằng, nhà sử học Lê Văn Hưu viết trong \"Đại Việt sử ký toàn thư\": \"Tiền Ngô vương có thể lấy quân mới họp của nước Việt ta mà đánh tan được trăm vạn quân của Lưu Hoằng Tháo, mở nước xưng vương, làm cho người phương Bắc không dám lại sang nữa. Có thể nói là một lần nổi giận mà yên được dân, mưu giỏi mà đánh cũng giỏi vậy. Tuy chỉ xưng vương, chưa lên ngôi đế, đổi niên hiệu, nhưng chính thống của nước Việt ta, ngõ hầu đã nối lại được\".\n\n','In China, in 907 the Tang Dynasty collapsed. Northern feudal militaristic groups both annexed and bloody destroyed each other, while taking advantage of every opportunity to expand and invade abroad. \n\nKing Liu Yan of Southern Han (later renamed Liu Gong) named the country Dai Han with the ambition to continue the expansion dream of the Dai Han empire in the early AD. The main direction of expansion of the Southern Han is the South, aimed at our country, a rich country and holding a key position in Southeast Asia, which has just passed more than a thousand years of Northern domination. \n\nTo realize that expansion dream, in 930, King Nam Han launched the first war of invasion. They defeated the Khuc government and captured Dai La citadel. In 931, a general of the Khuc family, Duong Dinh Nghe, raised troops from Asia, quickly wiped out the enemy troops from the country, and regained national sovereignty. \n\nIn 937, Duong Dinh Nghe was assassinated by Kieu Cong Tien to usurp the position of Lieutenant Governor. Kieu Cong Tien sent people to ask for help from King Nam Han. Taking advantage of that opportunity, Nam Han launched a second war of invasion of our country. \n\nThis time, King Nam Han sent his son, Crown Prince Giao Vuong Luu Hoang Thao, to command the navy to cross the sea and enter our country. King Nam Han also personally sent troops close to the border to support and gain prestige for his son and to be ready to respond when necessary.\n\nOctober 938, Ngo Quyen from the Asia region led troops to attack Kieu Cong Tien, eliminating internal threats and failing from the beginning the Southern Han\'s plot to use internal response. After that, he mobilized the people of the whole country to urgently enter the resistance war against the Southern Han invaders. \n\nOn the basis of promoting the nation\'s united strength and independent spirit, analyzing and evaluating our strengths and weaknesses and those of the enemy, Ngo Quyen presented a very determined, proactive and powerful posture to quickly destroy the enemy army. \n\nHe mobilized people to cut wood, sharpen it, cover it with iron, and build a pile at the mouth of the Bach Dang River. The marine army, with the participation of militia forces, arranged ambushes inside the stake yard, in the downstream area of ​​Bach Dang river. A fleet of light boats under the command of a young man from Gia Vien (Hai Phong), Nguyen Tat To, who was good at swimming and familiar with rivers and waters, was assigned the task of challenging, taking advantage of high tide to lure the enemy past the stakes and into our ambush trap inside. \n\nBach Dang is the gateway to the Northeast of our Fatherland, as the author of the history \"Cuong Muc\" said: \"The river is more than two miles wide, there are towering mountains, many river branches flowing together, waves reaching to the horizon, luxuriant trees covering the banks\". Ngo Quyen not only knew how to take advantage of natural terrain to hide troops in ambush, coordinate infantry with sailors, he was also the person who knew how to take advantage of the tides earliest in our country\'s military history, associated with the arrangement of the famous underground stake yard.\n\nIn Ngo Quyen\'s stance, the ambush inside the stake yard played a decisive role, stopping the enemy fleet and dealing them a sudden, heavy blow. The stake battlefield plays an important role, blocking the escape route of enemy ships and completely encircling and destroying the enemy army. The coordination between the two battlefields proves Ngo Quyen\'s strategic determination to not only defeat the enemy but also encircle and destroy all of the enemy\'s ships, winning a resounding victory, shattering the Southern Han Dynasty\'s dream of invasion and expansion. The \"stake battle\" is a unique feature of the Bach Dang battle, and is also a very early creation in Vietnamese military art whose initiator was Ngo Quyen.\n\nThe resistance war against the Southern Han invaders on the Bach Dang River took place fiercely and ended very quickly. \n\nNgo Quyen directly commanded the troops waiting in ambush inside the stakes, hiding troops in the river branches and on the right bank of the Bach Dang River. \n\nWhen Hoang Thao\'s army of large boats rushed across An Bang seaport and entered Bach Dang seaport, Ngo Quyen ordered the vanguard to use light boats to meet and attack the enemy from afar, creating a diversion to lure the enemy. When the high tide flooded the battlefield stakes, this part pretended to be defeated and fled to lure the enemy into the battlefield at the right time and place. General Hoang Thao arrogantly urged the army to chase quickly, fell for the trick, and crossed the underground pile.\n\nWaiting for the tide to go down, Ngo Quyen sent troops out in ambush to surround the enemy boats. The enemy\'s boat collided with a sharp iron stake and was punctured, most of it sank, and more than half of the troops drowned. Hoang Thao was stabbed by a spear and fell into the water, dying in battle. Our troops killed and captured most of the Southern Han army. The battle only took place within one day. Bach Dang\'s victory was so quick and unexpected that King Nam Han, who was leading support troops stationed at the border, had no time to respond. He was terrified and terrible, so he had to \"mournfully collect the remaining troops and retreat\" (Dai Viet Complete History) and \"bring the remaining people back\" (Ngu Great History).\n\nThe Bach Dang victory in 938 was recorded in the nation\'s history in general and the history of fighting foreign invaders in particular, as an important event with extremely great historical position and significance. This is considered an important milestone in the history of Vietnam. The victory helped destroy more than 1,000 years of Northern feudal domination, opening a period of true and lasting independence for our nation. \n\nNgo Quyen - the hero of the glorious victory on the Bach Dang River in 938 - became the king with \"regeneration, the king of kings\" according to the Complete Annals of Dai Viet. He deserves the title of \"father of renaissance\" of the nation as patriot Phan Boi Chau first stated in the national history of Vietnam.\n\nIn the spring of the year of the Pig (939), Ngo Quyen decided to quit his position as Tiet Do, proclaimed himself king and took the title Ngo Vuong Quyen, establishing an independent kingdom. Choosing the old capital of Au Lac, Co Loa, as the capital of Vietnam to show the intention to continue the tradition of the Hung and Thuc kings. \n\nPraising Ngo Quyen and the victory of Bach Dang, historian Le Van Huu wrote in \"Dai Viet Su Ky Toan Thu\": \"Tien Ngo King was able to use newly assembled troops of our country of Viet to defeat hundreds of thousands of Liu Hoang Thao\'s troops, open the country and declare himself king, making the Northerners not dare to come again. It can be said that once he was angry, he was able to calm the people, and he was good at planning but he was also good at fighting. Even though he only proclaimed himself king, he did not ascend to the throne, nor did he change the era name, but the country\'s legitimacy was still legitimate. Vietnam, so that we can reconnect.\"','/uploads/1775578972568-624036997.png','2026-04-07 16:22:56','2026-04-07 16:22:56'),(5,1930,'03-02-1930','February 3, 1930','Ngày thành lập Đảng Cộng sản Việt Nam','The founding date of the Communist Party of Vietnam','Từ ngày 3 đến 7-2-1930, tại Cửu Long (Hương Cảng, Trung Quốc), dưới sự chủ trì của đồng chí Nguyễn Ái Quốc, Hội nghị hợp nhất ba tổ chức Cộng sản ở Việt Nam là Đông Dương Cộng sản Đảng, An Nam Cộng sản Đảng, Đông Dương Cộng sản Liên đoàn, thành một đảng duy nhất là Đảng Cộng sản Việt Nam, với mục tiêu lãnh đạo phong trào cách mạng Việt Nam tiến hành giải phóng dân tộc, giải phóng giai cấp, giải phóng xã hội, giải phóng con người tiến lên chủ nghĩa xã hội.\n\nSự thống trị tàn bạo của thực dân Pháp đã làm cho mâu thuẫn dân tộc diễn ra hết sức gay gắt, hàng loạt phong trào yêu nước theo các khuynh hướng khác nhau liên tiếp nổ ra nhằm giải quyết mâu thuẫn chủ yếu đó. Tiêu biểu là phong trào Cần Vương do vua Hàm Nghi và Tôn Thất Thuyết khởi xướng; phong trào Đông Du của Phan Bội Châu; phong trào cải cách của Phan Chu Trinh, khởi nghĩa Yên Thế do Hoàng Hoa Thám lãnh đạo... Các cuộc đấu tranh giải phóng dân tộc tuy diễn ra quyết liệt, song cuối cùng đều bị thất bại, vì thiếu một đường lối cứu nước đúng đắn, thiếu một tổ chức lãnh đạo có khả năng tập hợp sức mạnh của toàn dân tộc. \n\nTrong bối cảnh đó, tháng 6-1911, người thanh niên yêu nước Nguyễn Tất Thành đã rời Tổ quốc ra đi tìm con đường cứu nước giải phóng dân tộc. Năm 1920 Nguyễn Tất Thành - Nguyễn Ái Quốc đã đến với chủ nghĩa Mác - Lênin; đây không chỉ là bước ngoặt đối với cuộc đời hoạt động cách mạng của Nguyễn Ái Quốc, mà còn là bước ngoặt của cách mạng Việt Nam. Lý luận của chủ nghĩa Mác - Lênin đã soi rọi cho Nguyễn Ái Quốc: Muốn cứu nước và giải phóng dân tộc thì trước hết phải có “Đảng cách mệnh” để “trong thì vận động và tổ chức dân chúng, ngoài thì liên lạc với dân tộc bị áp bức và vô sản giai cấp mọi nơi”. Từ nhận thức đó Nguyễn Ái Quốc ra sức chuẩn bị mọi mặt cho việc thành lập một chính đảng vô sản ở Việt Nam, Người từng bước truyền bá có hệ thống chủ nghĩa Mác - Lênin vào trong nước, đưa phong trào công nhân chuyển dần từ trình độ tự phát lên tự giác; đưa phong trào yêu nước chuyển dần sang lập trường cộng sản. \n\nTháng 3-1929, Chi bộ Cộng sản đầu tiên được thành lập ở số nhà 5D, Hàm Long, Hà Nội, gồm có Trần Văn Cung, Trịnh Đình Cửu, Ngô Gia Tự, Nguyễn Đức Cảnh, Đỗ Ngọc Du, Nguyễn Phong Sắc, Nguyễn Văn Tuân và Dương Hạc Đính. \n\nNgày 1-5-1929, tại Đại hội toàn quốc của Hội Việt Nam Cách mạng Thanh niên ở Hương Cảng (Trung Quốc), đoàn đại biểu Bắc Kỳ đưa ra đề nghị thành lập Đảng Cộng sản. Đề nghị đó không được chấp nhận, trở về nước, ngày 17-6-1929, những đảng viên trong Chi bộ Cộng sản 5D Hàm Long đã tuyên bố thành lập Đông Dương Cộng sản Đảng. Ngày 25-7-1929, An Nam Cộng sản Đảng được thành lập ở Nam Kỳ. Tháng 9-1929 Đông Dương Cộng sản Liên đoàn được thành lập ở Trung Kỳ. \n\nChỉ trong một thời gian ngắn ở Việt Nam đã có ba tổ chức cộng sản được tuyên bố thành lập. Điều đó phản ánh xu thế tất yếu của phong trào đấu tranh cách mạng ở Việt Nam. Song sự tồn tại của ba tổ chức cộng sản hoạt động biệt lập trong một quốc gia có nguy cơ dẫn đến chia rẽ lớn. Yêu cầu bức thiết của cách mạng là cần có một Đảng thống nhất lãnh đạo. Nguyễn Ái Quốc, người chiến sĩ cách mạng lỗi lạc của dân tộc Việt Nam, người duy nhất có đủ năng lực và uy tín đáp ứng yêu cầu đó của lịch sử: thống nhất các tổ chức cộng sản thành Đảng Cộng sản duy nhất ở Việt Nam. \n\nTừ ngày 3 đến 7-2-1930, Hội nghị hợp nhất ba tổ chức Cộng sản họp tại Cửu Long (Hương Cảng, Trung Quốc) dưới sự chủ trì của đồng chí Nguyễn Ái Quốc. Tham gia Hội nghị có các đồng chí Trịnh Đình Cửu, Nguyễn Đức Cảnh (đại biểu Đông Dương Cộng sản Đảng); Nguyễn Thiệu, Châu Văn Liêm (đại biểu An Nam Cộng sản Đảng). Đại biểu Đông Dương Cộng sản Liên đoàn không đến kịp. Hội nghị nhất trí thành lập đảng thống nhất, lấy tên là Đảng Cộng sản Việt Nam, thông qua Chánh cương vắn tắt, Sách lược vắn tắt, Chương trình tóm tắt và Điều lệ vắn tắt của Đảng. Ngày 3 tháng 2 năm 1930 trở thành Ngày thành lập Đảng Cộng sản Việt Nam. \n\nHội nghị hợp nhất các tổ chức cộng sản Việt Nam mang tầm vóc lịch sử như là Đại hội thành lập Đảng. Đảng Cộng sản Việt Nam được thành lập là kết quả của cuộc đấu tranh giai cấp và đấu tranh dân tộc ở nước ta trong những năm đầu thế kỷ XX; là sản phẩm cuả sự kết hợp chủ nghĩa Mác - Lênin với phong trào công nhân và phong trào yêu nước; là kết quả của quá trình lựa chọn, sàng lọc nghiêm khắc của lịch sử và là kết quả của quá trình chuẩn bị đầy đủ về chính trị, tư tưởng và tổ chức của một tập thể chiến sĩ cách mạng, đứng đầu là đồng chí Nguyễn Ái Quốc. \n\nĐó là một mốc lớn đánh dấu bước ngoặt trọng đại trong lịch sử cách mạng Việt Nam, chấm dứt cuộc khủng hoảng về đường lối cứu nước kéo dài mấy chục năm. Trong Chánh cương vắn tắt, Sách lược vắn tắt do đồng chí Nguyễn Ái Quốc khởi thảo, được Hội nghị thành lập Đảng thông qua đã xác định cách mạng Việt Nam phải tiến hành cách mạng giải phóng dân tộc tiến lên chủ nghĩa xã hội. Độc lập dân tộc và chủ nghĩa xã hội là con đường cách mạng duy nhất đúng để thực hiện mục tiêu giải phóng dân tộc, giải phóng giai cấp, giải phóng xã hội, giải phóng con người. Sự ra đời của Đảng Cộng sản Việt Nam với Cương lĩnh, đường lối cách mạng đúng đắn chứng tỏ giai cấp công nhân Việt Nam đã trưởng thành, đủ sức lãnh đạo cách mạng. \n\nSự ra đời của Đảng Cộng sản Việt Nam gắn liền với tên tuổi của Nguyễn Ái Quốc - Hồ Chí Minh, người sáng lập và rèn luyện Đảng ta./.','From February 3 to 7, 1930, in Kowloon (Hong Kong, China), under the chairmanship of comrade Nguyen Ai Quoc, the Conference merged three Communist organizations in Vietnam, namely the Indochina Communist Party, the Annam Communist Party, and the Indochina Communist Federation, into a single party, the Communist Party of Vietnam, with the goal of leading the Vietnamese revolutionary movement to carry out national liberation, class liberation, social liberation, and human liberation. move towards socialism.\n\nThe brutal domination of the French colonialists made national conflicts extremely fierce, and a series of patriotic movements of different trends continuously broke out to resolve that main conflict. Typically, the Can Vuong movement was initiated by King Ham Nghi and Ton That Thuyet; Dong Du movement of Phan Boi Chau; Phan Chu Trinh\'s reform movement, Yen The uprising led by Hoang Hoa Tham... Although the national liberation struggles took place fiercely, they all failed in the end, because of the lack of a correct way to save the country and a leadership organization capable of gathering the strength of the entire nation.\n\nIn that context, in June 1911, patriotic young man Nguyen Tat Thanh left his country to find a way to save the country and liberate the nation. In 1920, Nguyen Tat Thanh - Nguyen Ai Quoc came to Marxism - Leninism; This was not only a turning point in Nguyen Ai Quoc\'s revolutionary life, but also a turning point in the Vietnamese revolution. The theory of Marxism-Leninism enlightened Nguyen Ai Quoc: To save the country and liberate the nation, we must first have a \"Revolutionary Party\" to \"internally mobilize and organize the people, and externally communicate with the oppressed nation and the proletariat everywhere\". From that awareness, Nguyen Ai Quoc tried his best to prepare all aspects for the establishment of a proletarian political party in Vietnam. He gradually and systematically spread Marxism-Leninism into the country, bringing the workers\' movement gradually from the level of spontaneity to self-awareness; gradually shifted the patriotic movement to a communist stance.\n\nIn March 1929, the first Communist cell was established at house number 5D, Ham Long, Hanoi, including Tran Van Cung, Trinh Dinh Cuu, Ngo Gia Tu, Nguyen Duc Canh, Do Ngoc Du, Nguyen Phong Sac, Nguyen Van Tuan and Duong Hac Dinh.\n\nOn May 1, 1929, at the National Congress of the Vietnam Revolutionary Youth Association in Hong Kong (China), the Tonkin delegation proposed the establishment of the Communist Party. That proposal was not accepted. Returning to the country, on June 17, 1929, party members in the 5D Ham Long Communist Party announced the establishment of the Indochina Communist Party. On July 25, 1929, the Annam Communist Party was established in Cochinchina. In September 1929, the Indochina Communist Federation was established in Central Vietnam.\n\nIn just a short time in Vietnam, three communist organizations were declared established. That reflects the inevitable trend of the revolutionary movement in Vietnam. But the existence of three communist organizations operating separately in one country risks leading to major division. The urgent requirement of the revolution is the need for a unified Party to lead. Nguyen Ai Quoc, a prominent revolutionary soldier of the Vietnamese people, is the only person with the capacity and prestige to meet that requirement of history: unifying communist organizations into the only Communist Party in Vietnam.\n\nFrom February 3 to February 7, 1930, the Conference to unify three Communist organizations met in Kowloon (Hong Kong, China) under the chairmanship of comrade Nguyen Ai Quoc. Participating in the Conference were comrades Trinh Dinh Cuu and Nguyen Duc Canh (representatives of the Indochina Communist Party); Nguyen Thieu, Chau Van Liem (delegates of the Annam Communist Party). The representative of the Indochina Communist Federation did not arrive on time. The conference agreed to establish a unified party, named the Communist Party of Vietnam, and approved a brief Political Platform, brief Strategy, summary Program and brief Charter of the Party. February 3, 1930 became the Founding Day of the Communist Party of Vietnam.\n\nThe conference to unify Vietnamese communist organizations was as historic as the Party Establishment Congress. The Communist Party of Vietnam was established as a result of the class struggle and national struggle in our country in the early years of the twentieth century; is the product of the combination of Marxism-Leninism with the workers\' movement and the patriotic movement; is the result of a strict historical selection and screening process and the result of the full political, ideological and organizational preparation of a collective of revolutionary soldiers, headed by comrade Nguyen Ai Quoc.\n\nThat was a major milestone marking an important turning point in Vietnam\'s revolutionary history, ending the crisis over the country\'s salvation policy that had lasted for decades. In the brief Political Platform and Brief Strategy drafted by comrade Nguyen Ai Quoc and approved by the Party Establishment Conference, it was determined that the Vietnamese revolution must carry out a national liberation revolution and advance to socialism. National independence and socialism are the only correct revolutionary path to realize the goal of national liberation, class liberation, social liberation, and human liberation. The birth of the Communist Party of Vietnam with the correct revolutionary platform and guidelines proves that the Vietnamese working class has matured and is capable of leading the revolution.\n\nThe birth of the Communist Party of Vietnam is associated with the name of Nguyen Ai Quoc - Ho Chi Minh, the founder and trainer of our Party./.','/uploads/1775579746083-494615754.jpg','2026-04-07 16:35:48','2026-04-07 16:35:48'),(6,1945,'02-09-1945','September 2, 1945','Tuyên ngôn Độc lập','Declaration of Independence','Ngày 2 tháng 9 năm 1945, tại Quảng trường Ba Đình lịch sử, Chủ tịch Hồ Chí Minh đã thay mặt Chính phủ lâm thời đọc bản Tuyên ngôn Độc lập, khai sinh ra nước Việt Nam Dân chủ Cộng hòa. Đây không chỉ là một văn bản pháp lý đặt nền móng cho một kỷ nguyên mới, mà còn là một áng \"thiên cổ hùng văn\" kết tinh trí tuệ, khát vọng tự do và ý chí sắt đá của cả một dân tộc.\n\nMở đầu bản Tuyên ngôn, Hồ Chí Minh đã hết sức khéo léo và sắc sảo khi trích dẫn hai bản tuyên ngôn nổi tiếng thế giới: Tuyên ngôn Độc lập của Mỹ (1776) và Tuyên ngôn Nhân quyền và Dân quyền của Cách mạng Pháp (1791):\n- \"Tất cả mọi người đều sinh ra có quyền bình đẳng. Tạo hóa cho họ những quyền không ai có thể xâm phạm được; trong những quyền ấy, có quyền được sống, quyền tự do và quyền mưu cầu hạnh phúc.\"\n- \"Người ta sinh ra tự do và bình đẳng về quyền lợi; và phải luôn luôn được tự do và bình đẳng về quyền lợi.\"\n\nViệc trích dẫn này không chỉ nhằm mục đích tranh thủ sự ủng hộ của dư luận quốc tế mà còn là một đòn tấn công trực diện vào luận điệu của thực dân Pháp – những kẻ đang nhân danh \"tự do, bình đẳng, bác ái\" để đô hộ Việt Nam. Người đã nâng tầm quyền con người thành quyền dân tộc: Một dân tộc không có độc lập thì cá nhân không thể có tự do và hạnh phúc thực sự.\n\nSau khi thiết lập cơ sở pháp lý, Chủ tịch Hồ Chí Minh đã dùng những lý lẽ đanh thép để vạch trần bộ mặt thật của thực dân Pháp trong suốt hơn 80 năm cai trị. Người khẳng định: \"Thế mà hơn 80 năm nay, bọn thực dân Pháp lợi dụng lá cờ tự do, bình đẳng, bác ái, đến cướp đất nước ta, áp bức đồng bào ta. Hành động của chúng trái hẳn với nhân đạo và chính nghĩa.\"\n\nBản Tuyên ngôn liệt kê rõ ràng các tội ác trên mọi lĩnh vực:\n- Chính trị: Chúng tuyệt đối không cho dân ta một chút quyền tự do dân chủ nào, thi hành luật pháp dã man, ngăn cản việc thống nhất nước nhà.\n- Kinh tế: Chúng bóc lột dân ta đến xương tủy, khiến cho dân ta nghèo nàn, thiếu thốn; chúng giữ độc quyền xuất cảng và nhập cảng, đặt ra hàng trăm thứ thuế vô lý.\n- Văn hóa - Giáo dục: Chúng lập ra nhà tù nhiều hơn trường học, dùng thuốc phiện và rượu cồn để làm cho nòi giống ta suy nhược.\n\nĐặc biệt, Người nhấn mạnh sự hèn nhát của thực dân Pháp khi \"quỳ gối đầu hàng, mở cửa nước ta rước Nhật\" vào năm 1940. Từ đó, nhân dân Việt Nam chịu cảnh \"một cổ hai tròng\", dẫn đến thảm họa chết đói hơn hai triệu đồng bào năm 1945. Sự thật ấy khẳng định rằng Pháp không có công \"bảo hộ\" mà trái lại, đã phản bội đồng minh và bán nước ta hai lần cho Nhật.\n\nBản Tuyên ngôn khẳng định mạnh mẽ rằng nền độc lập của Việt Nam không phải là sự ban ơn, mà là kết quả của quá trình đấu tranh kiên cường: \"Pháp chạy, Nhật hàng, vua Bảo Đại thoái vị. Dân ta đã đánh đổ các xiềng xích thực dân gần 100 năm nay để gây nên nước Việt Nam độc lập. Dân ta lại đánh đổ chế độ quân chủ mấy mươi thế kỷ mà lập nên chế độ Dân chủ Cộng hòa.\"\n\nCâu văn này như một sự tổng kết lịch sử vĩ đại. Nó cho thấy sức mạnh của khối đại đoàn kết toàn dân tộc dưới sự lãnh đạo của Mặt trận Việt Minh. Việt Nam đã đứng về phe Đồng minh chống phát xít và xứng đáng được hưởng quyền tự do, độc lập.\n\nPhần kết của bản Tuyên ngôn Độc lập mang tính khẳng định tuyệt đối về chủ quyền quốc gia:\n\n\"Nước Việt Nam có quyền hưởng tự do và độc lập, và sự thật đã thành một nước tự do độc lập. Toàn thể dân tộc Việt Nam quyết đem tất cả tinh thần và lực lượng, tính mạng và của cải để giữ vững quyền tự do, độc lập ấy.\"\n\nĐây không chỉ là lời tuyên bố với thế giới mà còn là lời thề quyết tử của một dân tộc vừa mới rũ bùn đứng dậy sáng lòa. Nó thể hiện bản lĩnh của một quốc gia không bao giờ chịu khuất phục trước bất kỳ thế lực ngoại xâm nào.\n\nHơn 80 năm đã trôi qua, nhưng âm hưởng của bản Tuyên ngôn Độc lập 02/09/1945 vẫn còn vang vọng. Nó là ngọn đuốc soi đường cho các thế hệ người Việt Nam trong công cuộc xây dựng và bảo vệ Tổ quốc. Những tư tưởng về quyền sống, quyền tự do và quyền mưu cầu hạnh phúc mà Chủ tịch Hồ Chí Minh nêu ra vẫn còn nguyên giá trị thời đại, nhắc nhở chúng ta về cái giá của độc lập và trách nhiệm gìn giữ non sông gấm vóc.','On September 2, 1945, at Ba Dinh Square, President Ho Chi Minh read the Declaration of Independence, officially giving birth to the Democratic Republic of Vietnam. This document is not merely a legal text but a masterpiece of political rhetoric, crystallizing the wisdom, thirst for liberty, and the iron will of an entire nation.\n\nPresident Ho Chi Minh opened the Declaration by strategically quoting two world-renowned documents: the American Declaration of Independence (1776) and the French Declaration of the Rights of Man and of the Citizen (1791):\n- \"All men are created equal. They are endowed by their Creator with certain unalienable rights, among them are Life, Liberty, and the pursuit of Happiness.\"\n- \"All men are born free and with equal rights, and must always remain free and have equal rights.\"\n\nBy citing these, he did not just seek international sympathy; he launched a direct intellectual assault on the French colonialists. He pointed out the hypocrisy of those who ruled under the banner of \"Liberty, Equality, Fraternity\" while oppressing Vietnam. Crucially, he elevated human rights into national rights: a people cannot have individual freedom if the nation itself is not independent.\n\nAfter establishing a legal framework, the President used sharp, undeniable logic to strip away the facade of the French \"civilizing mission\" over the previous 80 years. He asserted: \"Nevertheless, for more than eighty years, the French imperialists, abusing the standard of Liberty, Equality, and Fraternity, have violated our Fatherland and oppressed our fellow-citizens. They have acted contrary to the ideals of humanity and justice.\"\n\nThe Declaration meticulously listed their crimes across all sectors:\n- Politics: Depriving the people of democratic liberties, enforcing inhuman laws, and dividing the nation into three distinct political regimes to prevent national unity.\n- Economics: Exploiting the people to the bone, monopolizing resources, and imposing hundreds of unjust taxes, leading to extreme poverty.\n- Culture & Education: Building more prisons than schools and using opium and alcohol to weaken the vitality of the Vietnamese race.\n\nMost notably, he highlighted French cowardice during World War II. In 1940, instead of \"protecting\" the country, the French \"knelt down and opened the gates to the Japanese.\" This resulted in a double yoke of oppression that led to the horrific famine of 1945, claiming over two million lives.\n\nThe Declaration firmly stated that Vietnam’s independence was not a gift but a hard-won victory: \"The French have fled, the Japanese have capitulated, Emperor Bao Dai has abdicated. Our people have broken the chains which for nearly a century have fettered them and have won independence for the Fatherland. Our people at the same time have overthrown the monarchic regime that has reigned supreme for dozens of centuries. In its place has been established the present Democratic Republic.\"\n\nThis summary of history proved that the Vietnamese people, led by the Viet Minh, had stood on the side of the Allies against Fascism. Therefore, Vietnam deserved to be free and independent.\n\nThe conclusion of the document serves as an absolute affirmation of national sovereignty:\n\n\"Vietnam has the right to be a free and independent country—and in fact is so already. And thus the entire Vietnamese people are determined to mobilize all their physical and mental strength, to sacrifice their lives and property in order to safeguard their independence and liberty.\"\n\nThis was more than a statement to the world; it was a \"death-defying\" oath of a nation that had just risen from the ashes of slavery.\n\nOver 80 years have passed, but the echoes of the Declaration of Independence of September 2, 1945, remain vibrant. It is the torch that guides generations of Vietnamese in building and defending their country. The ideals of the right to live, the right to be free, and the right to pursue happiness are timeless, reminding us of the price of independence and the sacred duty to preserve the nation\'s heritage.','/uploads/1775580351333-728301568.jpg','2026-04-07 16:46:12','2026-04-07 16:46:12'),(7,1975,'30-04-1975','April 30, 1975','Giải phóng miền Nam - Thống nhất đất nước','Liberating the South - Reuniting the Country','Ngày 30 tháng 4 năm 1975 đã đi vào lịch sử dân tộc Việt Nam như một mốc son chói lọi nhất của thế kỷ XX. Đó là thời khắc lá cờ cách mạng tung bay trên nóc Dinh Độc Lập, đánh dấu sự sụp đổ hoàn toàn của chế độ Việt Nam Cộng hòa, kết thúc 21 năm chia cắt hai miền Nam - Bắc và mở ra một kỷ nguyên mới: kỷ nguyên của độc lập, thống nhất và cả nước đi lên Chủ nghĩa Xã hội.\n\nSau hiệp định Paris năm 1973, cục diện chiến trường miền Nam có những thay đổi căn bản có lợi cho ta. Nhận thấy thời cơ vàng đã đến, Bộ Chính trị Trung ương Đảng đã đề ra quyết tâm chiến lược: Giải phóng hoàn toàn miền Nam trong hai năm 1975 - 1976, nhưng nếu thời cơ đến vào đầu hoặc cuối năm 1975 thì lập tức giải phóng miền Nam trong năm 1975.\n\nCuộc Tổng tiến công và nổi dậy Mùa Xuân năm 1975 bắt đầu bằng ba đòn chiến lược then chốt:\n\n- Chiến dịch Tây Nguyên: Mở đầu bằng trận đột phá chiến lược tại Buôn Ma Thuột (10/3), khiến hệ thống phòng thủ của đối phương rung chuyển và tan rã.\n\n- Chiến dịch Huế - Đà Nẵng: Quét sạch sinh lực địch tại dải đất miền Trung, tạo thế gọng kìm uy hiếp trực tiếp vào sào huyệt cuối cùng là Sài Gòn.\n\n- Chiến dịch Hồ Chí Minh: Chiến dịch quyết chiến chiến lược cuối cùng, bắt đầu từ ngày 26/4.\n\nChiến dịch Hồ Chí Minh là sự hội tụ sức mạnh tổng hợp của cả dân tộc. Với phương châm \"Thần tốc, táo bạo, bất ngờ, chắc thắng\", năm cánh quân từ các hướng Đông, Tây Bắc, Đông Bắc, Tây Nam và phía Nam đã đồng loạt tiến công vào các cơ quan đầu não của địch tại Sài Gòn.\n\nSáng ngày 30/4, các đơn vị tinh nhuệ của quân đội ta phối hợp với lực lượng tại chỗ tiến sâu vào nội đô. Những chiếc xe tăng thuộc Lữ đoàn 203, Quân đoàn 2 đã húc đổ cánh cổng Dinh Độc Lập. Đúng 11 giờ 30 phút, lá cờ của Mặt trận Dân tộc Giải phóng miền Nam Việt Nam tung bay trên đỉnh Dinh, báo hiệu sự kết thúc của một cuộc chiến tranh vệ quốc vĩ đại. Tổng thống Dương Văn Minh của chính quyền Sài Gòn phải tuyên bố đầu hàng không điều kiện.\n\nĐại thắng mùa Xuân 1975 không chỉ là thắng lợi của quân sự mà còn là thắng lợi của ý chí, khát vọng hòa bình và sự đoàn kết dân tộc.\n\n- Đối với dân tộc: Chấm dứt ách thống trị của chủ nghĩa thực dân mới, hoàn thành cuộc cách mạng dân tộc dân chủ nhân dân trên cả nước. Đây là thành quả của 30 năm chiến đấu không ngừng nghỉ kể từ Cách mạng Tháng Tám năm 1945.\n\n- Đối với quốc tế: Thắng lợi này đã đập tan cuộc thử nghiệm lớn nhất của chủ nghĩa đế quốc sau Thế chiến II, cổ vũ mạnh mẽ phong trào giải phóng dân tộc trên toàn thế giới, khẳng định rằng một dân tộc dù nhỏ bé nhưng có ý chí sắt đá và đường lối đúng đắn hoàn toàn có thể chiến thắng những cường quốc hùng mạnh nhất.\n\nChiến thắng 30/4 để lại nhiều bài học quý báu cho công cuộc xây dựng và bảo vệ Tổ quốc hôm nay:\n\n- Sức mạnh đoàn kết: \"Đoàn kết, đoàn kết, đại đoàn kết - Thành công, thành công, đại thành công\".\n\n- Tinh thần tự lực tự cường: Dựa vào sức mình là chính đồng thời tranh thủ sự ủng hộ của bạn bè quốc tế.\n\n- Khát vọng hòa bình: Hiểu rõ giá trị của xương máu cha ông để trân trọng sự bình yên hôm nay.','April 30, 1975, stands as the most brilliant milestone in the 20th-century history of the Vietnamese people. It was the moment when the revolutionary flag flew atop the Independence Palace, marking the complete collapse of the Republic of Vietnam regime, ending 21 years of national division, and ushering in a new era: the era of independence, unification, and national progress toward Socialism.\n\nFollowing the 1973 Paris Peace Accords, the landscape of the southern battlefield shifted fundamentally in favor of the revolutionary forces. Recognizing the \"golden opportunity,\" the Party Central Committee set a strategic goal: to completely liberate the South within 1975-1976, but with an immediate push for victory in 1975 should the opportunity arise.\n\nThe General Offensive and Uprising of Spring 1975 unfolded through three key strategic strikes:\n\n- The Central Highlands Campaign: Triggered by the strategic breakthrough at Buon Ma Thuot (March 10), which caused the enemy\'s defense system to shake and crumble.\n\n- The Hue - Da Nang Campaign: Sweeping away enemy forces in Central Vietnam and creating a pincer movement threatening the final stronghold of Saigon.\n\n- The Ho Chi Minh Campaign: The final decisive strategic battle, commencing on April 26.\n\nThe Ho Chi Minh Campaign was a convergence of the entire nation\'s combined strength. Under the motto \"Lightning speed, audacity, surprise, and certain victory,\" five army columns from the East, Northwest, Northeast, Southwest, and South launched a simultaneous assault on enemy nerve centers in Saigon.\n\nOn the morning of April 30, elite units coordinated with local forces to penetrate the city center. Tanks from the 203rd Brigade, 2nd Corps, crashed through the gates of the Independence Palace. At exactly 11:30 AM, the flag of the National Liberation Front of South Vietnam was raised over the palace, signaling the end of a great war of national defense. President Duong Van Minh of the Saigon administration was forced to declare an unconditional surrender.\n\nThe 1975 Spring Victory was not merely a military triumph; it was a victory of will, the yearning for peace, and national solidarity.\n\n- For the Nation: It ended the yoke of neo-colonialism and completed the national people\'s democratic revolution across the country. This was the fruit of 30 years of relentless struggle since the August Revolution of 1945.\n\n- Internationally: This victory shattered the largest imperialist experiment post-WWII, strongly encouraging national liberation movements worldwide. It proved that a nation, though small, can defeat the most powerful empires if it possesses an iron will and a correct strategic path.\n\nThe April 30 victory leaves behind precious lessons for the construction and protection of the Fatherland today:\n\n- The Power of Unity: National solidarity remains the core strength of the country.\n\n- Spirit of Self-Reliance: Relying primarily on our own strength while garnering international support.\n\n- The Aspiration for Peace: Understanding the immense sacrifices made by previous generations to cherish the peace we enjoy today.','/uploads/1775580986362-528495820.jpg','2026-04-07 16:56:29','2026-04-07 16:56:29'),(8,2024,'22-12-2024','December 22, 2024','Kỷ niệm 80 năm Ngày thành lập QĐND Việt Nam, 35 năm Ngày hội QPTD','80th anniversary of the founding of the People\'s Republic of Vietnam, 35th anniversary of the DPRK','Kỷ niệm 80 năm Ngày thành lập Quân đội nhân dân Việt Nam và 35 năm Ngày hội Quốc phòng toàn dân là dịp để chúng ta ôn lại lịch sử vẻ vang của dân tộc và những chiến công oanh liệt của quân và dân ta; khơi dậy niềm tự hào dân tộc, chủ nghĩa anh hùng cách mạng, ý chí tự lực, tự cường vượt qua mọi khó khăn, thử thách…\n\nQUÂN ĐỘI NHÂN DÂN VIỆT NAM – 80 NĂM XÂY DỰNG VÀ TRƯỞNG THÀNH\n\nNgày 22/12/1944, tại khu rừng thuộc huyện Nguyên Bình (Cao Bằng), Đội Việt Nam Tuyên truyền Giải phóng quân đã chính thức làm lễ thành lập, gồm 03 tiểu đội với 34 chiến sĩ được lựa chọn từ những chiến sĩ Cao-Bắc-Lạng, do đồng chí Võ Nguyên Giáp trực tiếp chỉ huy. Đây là đơn vị chủ lực đầu tiên của lực lượng vũ trang cách mạng và là tiền thân của Quân đội nhân dân Việt Nam.\n\nĐội Việt Nam tuyên truyền giải phóng quân do đồng chí Hoàng Sâm làm đội trưởng, đồng chí Xích Thắng (Dương Mạc Thạch) làm chính trị viên, đồng chí Hoàng Văn Thái phụ trách Kế hoạch-Tình báo, đồng chí Vân Tiên (Lộc Văn Lùng) quản lý. Đội có chi bộ Đảng lãnh đạo. Dù chỉ có 34 người, với 34 khẩu súng các loại nhưng họ là những chiến sĩ kiên quyết, dũng cảm trong các đội du kích Cao-Bắc-Lạng, Cứu quốc quân,… là con em các tầng lớp Nhân dân bị áp bức, họ có lòng yêu nước, chí căm thù địch rất cao, đã siết chặt họ thành một khối vững chắc, không kẻ thù nào phá vỡ.\n\nChấp hành chỉ thị “phải đánh thắng trận đầu”, ngay sau ngày thành lập, Đội Việt Nam tuyên truyền giải phóng quân đã mưu trí, táo bạo, bất ngờ đột nhập vào đồn Phai Khắt (17 giờ chiều 25-12-1944) và sáng hôm sau (7 giờ ngày 26-12-1944) đột nhập đồn Nà Ngần, tiêu diệt gọn 2 đồn địch, giết chết 2 tên đồn trưởng, bắt sống toàn bộ binh lính, thu toàn bộ vũ khí, quân trang, quân dụng. Hai trận đánh đồn Phai Khắt, Nà Ngần thắng lợi đã mở đầu truyền thống đánh tiêu diệt, đánh chắc thắng, đánh thắng trận đầu của quân đội ta suốt hai cuộc kháng chiến chống Pháp và chống Mỹ cho đến ngày thắng lợi hoàn toàn.\n\nTrải qua 80 năm xây dựng, chiến đấu và trưởng thành, Quân đội ta thực sự là quân đội anh hùng của một dân tộc anh hùng; là lực lượng chính trị; lực lượng chiến đấu tuyệt đối trung thành, tin cậy của Đảng, Nhà nước và nhân dân ; làm tròn chức năng đội quân chiến đấu, đội quân công tác, đội quân lao động sản xuất, xứng đáng với lời khen ngợi của Chủ Tịch Hồ Chí Minh: “Quân đội ta trung với Đảng, hiếu với dân, sẵn sàng chiến đấu hy sinh vì độc lập, tự do của Tổ quốc, vì chủ nghĩa xã hội. Nhiệm vụ nào cũng hoàn thành, khó khăn nào cũng vượt qua, kẻ thù nào cũng đánh thắng”.\n\nBước vào thời kỳ xây dựng và bảo vệ Tổ quốc, Quân đội ta luôn hoàn thành thắng lợi mọi nhiệm vụ mà Đảng, Nhà nước giao; không ngừng xây dựng Quân đội vững mạnh về chính trị , chính quy, tinh nhuệ và từng bước hiện đại; rèn luyện kỷ luật, khả năng sẵn sàng chiến đấu, không để bị động, bất ngờ trước mọi tình huống trong quá trình xây dựng và bảo vệ Tổ quốc Việt Nam xã hội chủ nghĩa; bảo vệ hòa bình ổn định, phát triển trong khu vực và trên thế giới, xứng đáng với tên gọi “Quân đội Nhân dân Việt Nam anh hùng”.\n\nTừ vai trò, vị trí đã được khẳng định của chiến tranh nhân dân, toàn dân, toàn diện qua các cuộc kháng chiến dưới sự lãnh đạo của Đảng, thể theo nguyện vọng của Nhân dân cả nước, ngày 17 tháng 10 năm 1989, Ban Bí thư Trung ương Đảng( khóa VI) đã ra Chỉ thị số 381 – CT/TW, quyết định lấy ngày thành lập Quân đội Nhân dân Việt Nam (22/12) đồng thời là Ngày Hội quốc phòng toàn dân. Từ đây, ngày 22 tháng 12 thực sự trở thành ngày hội truyền thống bảo vệ Tổ quốc, ngày hội tôn vinh và nhân lên hình ảnh cao đẹp “Bộ đội Cụ Hồ” – một nét đẹp độc đáo của văn hóa dân tộc Việt Nam trong thời đại mới. Đây cũng là dịp phát huy truyền thống yêu nước, biểu dương sức mạnh đại đoàn kết toàn dân tộc và quyết tâm của toàn Đảng, toàn dân, toàn quân ta trong sự nghiệp xây dựng và bảo vệ vững chắc Tổ quốc Việt Nam xã hội chủ nghĩa trong thời kỳ mới. Xây dựng nền quốc phòng toàn dân là nhân tố cốt lõi, nền tảng để đất nước ta tăng cường sức mạnh quốc phòng, bảo vệ Tổ quốc.\n\nTự hào về chiến công vĩ đại và truyền thống vẻ vang của Quân đội Nhân dân Việt Nam, trải qua 80 năm xây dựng, chiến đấu và trưởng thành, có thể khẳng định Quân đội Nhân dân Việt Nam là một quân đội anh hùng của một dân tộc anh hùng, xứng đáng với lời khen ngợi của Chủ tịch Hồ Chí Minh : “Quân đội ta trung với Đảng, hiếu với dân, sẵn sàng chiến đấu hy sinh vì độc lập, tự do của Tổ quốc, vì chủ nghĩa xã hội. Nhiệm vụ nào cũng hoàn thành, khó khăn nào cũng vượt qua, kẻ thù nào cũng đánh thắng”, góp phần thực hiện thắng lợi sự nghiệp Công nghiệp hóa, hiện đại hóa đất nước, vì mục tiêu “Dân giàu, nước mạnh, dân chủ, công bằng, văn minh”.\n\n 35 NĂM THỰC HIỆN NGÀY HỘI QUỐC PHÒNG TOÀN DÂN (22/12/1989 – 22/12/2024)\n\nNgày 17 tháng 10 năm 1989, Ban Bí thư Trung ương Đảng (khóa VI) đã ra Chỉ thị số 381-CT/TW quyết định lấy Ngày thành lập Quân đội nhân dân Việt Nam (22/12) đồng thời là Ngày hội Quốc phòng toàn dân – Ngày hội của truyền thống bảo vệ Tổ quốc, Ngày hội tôn vinh và nhân lên hình ảnh cao đẹp “Bộ đội Cụ Hồ” – một nét độc đáo của văn hóa dân tộc Việt Nam trong thời đại mới. Ngày hội Quốc phòng toàn dân cũng là dịp để phát huy truyền thống yêu nước, biểu dương sức mạnh đại đoàn kết toàn dân tộc và quyết tâm của toàn Đảng, toàn dân, toàn quân ta trong sự nghiệp xây dựng và bảo vệ vững chắc Tổ quốc Việt Nam xã hội chủ nghĩa.\n\nKỷ niệm 80 năm Ngày thành lập Quân đội nhân dân Việt Nam và 35 năm Ngày hội Quốc phòng toàn dân là dịp để chúng ta ôn lại lịch sử vẻ vang của dân tộc và những chiến công oanh liệt của quân và dân ta; khơi dậy niềm tự hào dân tộc, chủ nghĩa anh hùng cách mạng, ý chí tự lực, tự cường vượt qua mọi khó khăn, thử thách; ra sức xây dựng nền quốc phòng toàn dân vững mạnh, xây dựng Quân đội nhân dân Việt Nam cách mạng, chính quy, tinh nhuệ, từng bước hiện đại, là lực lượng chính trị tin cậy, đội quân chiến đấu trung thành của Đảng, Nhà nước và Nhân dân, đáp ứng yêu cầu nhiệm vụ trong thời kỳ mới của cách mạng, góp phần xứng đáng vào sự nghiệp xây dựng thành công chủ nghĩa xã hội và bảo vệ vững chắc Tổ quốc Việt Nam xã hội chủ nghĩa.','The commemoration of the 80th anniversary of the founding of the Vietnam People\'s Army and the 35th anniversary of All-People\'s Defense Day is an opportunity for us to reflect on the glorious history of our nation and the heroic feats of our army and people. It serves to kindle national pride, revolutionary heroism, and the spirit of self-reliance to overcome all difficulties and challenges.\n\nTHE VIETNAM PEOPLE\'S ARMY – 80 YEARS OF CONSTRUCTION AND GROWTH\nOn December 22, 1944, in a forest in Nguyen Binh District, Cao Bang Province, the Vietnam Propaganda Unit for the Liberation Army was officially established. The unit consisted of three squads with 34 soldiers selected from the guerrilla forces of Cao Bang, Bac Kan, and Lang Son, under the direct command of Comrade Vo Nguyen Giap. This was the first main force of the revolutionary armed forces and the predecessor of the Vietnam People\'s Army.\n\nThe unit was led by Captain Hoang Sam, with Comrade Xich Thang (Duong Mac Thach) as Political Officer, Comrade Hoang Van Thai in charge of Intelligence and Planning, and Comrade Van Tien (Loc Van Lung) as Manager. The unit was guided by a Party cell. Although numbering only 34 people with 34 various firearms, they were determined and brave soldiers from the guerrilla and National Salvation Army groups. As children of the oppressed classes, their deep patriotism and hatred for the enemy forged them into a solid bloc that no enemy could break.\n\nExecuting the directive to \"win the first battle,\" immediately after its formation, the unit acted with ingenuity and audacity. They unexpectedly infiltrated Phai Khat post at 5:00 PM on December 25, 1944, and Na Ngan post the following morning at 7:00 AM on December 26, 1944. They completely wiped out both enemy posts, killed both post commanders, captured all remaining soldiers, and seized all weapons and military equipment. These two victories initiated the tradition of \"determined to win\" and \"winning the opening battle\" that characterized our army throughout the resistance wars against the French and the Americans until final victory.\n\nThrough 80 years of construction, combat, and growth, our Army has truly become the heroic army of a heroic nation. It is a political force and a combat force absolutely loyal to and trusted by the Party, the State, and the People. It fulfills its functions as a fighting force, a working force, and a production force, deserving of President Ho Chi Minh\'s praise:\"Our Army is loyal to the Party, devoted to the people, and ready to fight and sacrifice for the independence and freedom of the Fatherland and for socialism. It completes any task, overcomes any difficulty, and defeats any enemy.\"\n\nEntering the era of national construction and protection, our Army has successfully fulfilled every mission assigned by the Party and State. It continuously builds its strength in terms of politics, regularity, and elite status, moving toward modernization. The army hones its discipline and combat readiness to ensure it is never caught by surprise in any situation, protecting peace and stability in the region and the world, worthy of the title \"Heroic Vietnam People\'s Army.\"\n\nBased on the established role of \"People\'s War\" through various resistance periods, and in accordance with the aspirations of the people, on October 17, 1989, the Secretariat of the Party Central Committee (6th Tenure) issued Directive No. 381-CT/TW. This directive designated the founding anniversary of the Vietnam People\'s Army (December 22) as All-People\'s Defense Day. Since then, December 22 has become a traditional festival for national defense, honoring and magnifying the noble image of \"Uncle Ho\'s Soldiers\"—a unique feature of Vietnamese culture in the new era. It is also an occasion to promote patriotism and demonstrate the strength of great national unity in the cause of firmly protecting the Socialist Republic of Vietnam.\n\n35 YEARS OF IMPLEMENTING ALL-PEOPLE\'S DEFENSE DAY (22/12/1989 – 22/12/2024)\nThe designation of All-People\'s Defense Day on December 22 serves as a festival for the tradition of national protection and a tribute to \"Uncle Ho\'s Soldiers.\" It is a time to manifest the determination of the entire Party, people, and army in the cause of building and safeguarding the Fatherland.\n\nCommemorating these milestones is an occasion to review our heroic history, arouse revolutionary heroism, and strengthen our resolve to build a strong all-people defense. We aim to build a Vietnam People’s Army that is revolutionary, regular, elite, and gradually modern—a reliable political force and a loyal fighting army of the Party, State, and People, meeting the requirements of the new revolutionary period and contributing worthily to the successful construction of socialism and the protection of the Socialist Republic of Vietnam.','/uploads/1775583002804-271255788.jpg','2026-04-07 17:30:04','2026-04-07 17:30:04');
